#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

// For large number arithmetic, we'd normally use GMP
// This implementation uses standard library for demonstration
// For production crypto, use: gcc -lgmp bbs.c

typedef struct {
    long long p;
    long long q;
    long long M;
    long long state;
} BBS_Generator;

// Extended Euclidean Algorithm for GCD
long long gcd(long long a, long long b) {
    while (b != 0) {
        long long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

// Miller-Rabin primality test
int isPrime(long long n) {
    if (n < 2) return 0;
    if (n == 2 || n == 3) return 1;
    if (n % 2 == 0) return 0;
    if (n < 9) return 0;

    // Write n-1 as 2^r * d
    long long d = n - 1;
    int r = 0;
    while (d % 2 == 0) {
        d /= 2;
        r++;
    }

    // Test with a few bases (simplified for demo)
    long long bases[] = {2, 3, 5, 7, 11, 13};
    int num_bases = 6;

    for (int i = 0; i < num_bases && bases[i] < n; i++) {
        long long a = bases[i];
        long long x = 1;
        long long base = a;
        long long exp = d;

        while (exp > 0) {
            if (exp % 2 == 1)
                x = (x * base) % n;
            base = (base * base) % n;
            exp /= 2;
        }

        if (x == 1 || x == n - 1)
            continue;

        int composite = 1;
        for (int j = 1; j < r; j++) {
            x = (x * x) % n;
            if (x == n - 1) {
                composite = 0;
                break;
            }
        }
        if (composite)
            return 0;
    }

    return 1;
}

// Simple prime generation (for small primes)
long long generate_prime(int bits) {
    long long lower = 1 << (bits - 1);
    long long upper = (1 << bits) - 1;

    for (long long n = upper; n >= lower; n -= 2) {
        if (isPrime(n) && (n % 4 == 3))
            return n;
    }
    return 0;
}

// Initialize BBS generator
BBS_Generator* bbs_init(long long p, long long q, long long seed) {
    if (!isPrime(p) || !isPrime(q)) {
        printf("Error: Both p and q must be prime\n");
        return NULL;
    }

    if (p % 4 != 3 || q % 4 != 3) {
        printf("Warning: p and q should be ≡ 3 (mod 4) for security\n");
    }

    BBS_Generator* bbs = (BBS_Generator*)malloc(sizeof(BBS_Generator));
    bbs->p = p;
    bbs->q = q;
    bbs->M = p * q;
    bbs->state = seed % bbs->M;

    if (gcd(bbs->state, bbs->M) != 1) {
        printf("Warning: seed should be coprime to p*q\n");
        bbs->state = (seed + 1) % bbs->M;
    }

    return bbs;
}

// Generate next random number
long long bbs_next(BBS_Generator* bbs) {
    // x_{n+1} = x_n^2 mod M
    bbs->state = (bbs->state * bbs->state) % bbs->M;
    return bbs->state;
}

// Generate random bits
int bbs_next_bits(BBS_Generator* bbs, int num_bits) {
    long long val = bbs_next(bbs);
    int mask = (1 << num_bits) - 1;
    return (int)(val & mask);
}

// Free generator
void bbs_free(BBS_Generator* bbs) {
    free(bbs);
}

// Demonstration
void demo_basic() {
    printf("=== Blum Blum Shub Generator - C Implementation ===\n\n");

    // Textbook example: p=17, q=23, seed=3
    long long p = 17, q = 23, seed = 3;

    printf("Basic Demo (Textbook Example):\n");
    printf("p = %lld, q = %lld, M = %lld\n", p, q, p*q);
    printf("seed = %lld\n\n", seed);

    BBS_Generator* bbs = bbs_init(p, q, seed);
    if (!bbs) return;

    printf("Generated Sequence:\n");
    for (int i = 1; i <= 10; i++) {
        long long val = bbs_next(bbs);
        printf("  s_%d = %lld\n", i, val);
    }

    printf("\n8-bit extraction demo:\n");
    bbs->state = seed; // Reset
    for (int i = 1; i <= 10; i++) {
        int val = bbs_next_bits(bbs, 8);
        printf("  byte_%d = %3d (0x%02X)\n", i, val, val);
    }

    bbs_free(bbs);
}

void demo_large_primes() {
    printf("\n=== Larger Primes Demo ===\n");

    // Generate small primes for demo (16-bit range)
    long long p = generate_prime(8);  // ~8 bit prime
    long long q = generate_prime(8);

    if (p == 0 || q == 0) {
        printf("Could not generate suitable primes\n");
        return;
    }

    printf("Generated primes:\n");
    printf("p = %lld (≡ 3 mod 4: %s)\n", p, (p%4==3)?"yes":"no");
    printf("q = %lld (≡ 3 mod 4: %s)\n", q, (q%4==3)?"yes":"no");

    long long seed = 2;
    BBS_Generator* bbs = bbs_init(p, q, seed);

    printf("\nFirst 10 values:\n");
    for (int i = 1; i <= 10; i++) {
        printf("  %lld\n", bbs_next(bbs));
    }

    bbs_free(bbs);
}

int main() {
    demo_basic();
    demo_large_primes();

    printf("\n=== Security Note ===\n");
    printf("For cryptographic security, use primes of 512+ bits.\n");
    printf("The difficulty of factoring M = p*q provides the security.\n");

    return 0;
}
